class Base:
    def __init__(self, name):
        self.name = name
    def __str__(self):
        return f"Base({self.name})"

class Middle(Base):
    def __init__(self, name, level):
        super().__init__(name)
        self.level = level
    def __str__(self):
        return super().__str__() + f" Level:{self.level}"

class Top(Middle):
    def __init__(self, name, level, rank):
        super().__init__(name, level)
        self.rank = rank
    def __str__(self):
        return super().__str__() + f" Rank:{self.rank}"

obj = Top("Alice", 3, "Gold")
print(obj)
```

