from abc import ABC, abstractmethod

class Vehicle(ABC):
    @abstractmethod
    def accelerate(self, amount):
        pass

    @abstractmethod
    def brake(self, amount):
        pass

class Car(Vehicle):
    def __init__(self, make):
        self.make = make
        self.speed = 0.0

    def accelerate(self, amount):
        if self.speed + amount > 200:
            raise ValueError('Speed limit exceeded')
        self.speed += amount

    def brake(self, amount):
        self.speed = max(0, self.speed - amount)

class ElectricCar(Car):
    def __init__(self, make, battery):
        super().__init__(make)
        self.battery = battery

    def accelerate(self, amount):
        super().accelerate(amount)  # raises ValueError if limit exceeded
        print(f'Battery at {self.battery}%')

def main():
    ec = ElectricCar('Tesla', 80)
    ec.accelerate(80)   # speed = 80, prints Battery at 80%
    ec.accelerate(80)   # speed = 160, prints Battery at 80%
    try:
        ec.accelerate(80)  # would be 240 > 200 → ValueError
    except ValueError as e:
        print(f'Error: {e}')

main()
```
